import React, { useState } from 'react';
import axios from 'axios';

function ClientDashboard() {
  const [email, setEmail] = useState('');
  const [project, setProject] = useState(null);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    setProject(null);
    setLoading(true);

    try {
      // १. ईमेलला 'toLowerCase' मध्ये रूपांतरित करा जेणेकरून मॅचिंगमध्ये अडचण येणार नाही
      const cleanEmail = email.trim().toLowerCase();
      
      // २. Backend API कॉल (तुमच्या server.js मधील /api/track/:email नुसार)
      const res = await axios.get(`http://localhost:5000/api/track/${cleanEmail}`);

      if (res.data) {
        setProject(res.data);
      }
    } catch (err) {
      // ३. जर डेटा सापडला नाही तर योग्य मेसेज दाखवणे
      if (err.response && err.response.status === 404) {
        setError("❌ या ईमेलवर कोणताही प्रोजेक्ट सापडला नाही. कृपया बरोबर ईमेल टाका.");
      } else {
        setError("❌ सर्व्हरशी संपर्क होऊ शकला नाही. Backend चालू आहे का तपासा.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container py-5 mt-4">
      {!project ? (
        /* लॉगिन विभाग */
        <div className="row justify-content-center">
          <div className="col-md-5">
            <div className="card shadow-lg border-0 p-4 rounded-4 text-center">
              <h3 className="fw-bold mb-3 text-primary">Client Dashboard</h3>
              <p className="text-muted mb-4">तुमच्या प्रोजेक्टची प्रगती पाहण्यासाठी ईमेल टाका.</p>
              <form onSubmit={handleLogin}>
                <input 
                  type="email" 
                  className="form-control mb-3 py-2 text-center" 
                  placeholder="तुमचा नोंदणीकृत ईमेल" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  required 
                />
                <button className="btn btn-primary w-100 fw-bold py-2 shadow" disabled={loading}>
                  {loading ? "लोड होत आहे..." : "प्रोजेक्ट पहा"}
                </button>
              </form>
              {error && <div className="text-danger mt-3 small">{error}</div>}
            </div>
          </div>
        </div>
      ) : (
        /* प्रत्यक्ष डॅशबोर्ड - डेटा सापडल्यानंतर */
        <div className="row justify-content-center">
          <div className="col-lg-8">
            <div className="card shadow-lg border-0 rounded-4 overflow-hidden">
              <div className="bg-primary p-4 text-white d-flex justify-content-between align-items-center">
                <h4 className="mb-0 fw-bold">नमस्कार, {project.fullName}!</h4>
                <button className="btn btn-sm btn-outline-light" onClick={() => setProject(null)}>Logout</button>
              </div>
              
              <div className="card-body p-4 p-lg-5">
                <div className="row g-4 mb-4">
                  <div className="col-md-6">
                    <div className="p-3 border rounded-3 bg-light">
                      <small className="text-muted d-block">Project Type</small>
                      <h5 className="fw-bold">{project.serviceType}</h5>
                    </div>
                  </div>
                  <div className="col-md-6">
                    <div className="p-3 border rounded-3 bg-light">
                      <small className="text-muted d-block">Payment Status</small>
                      <h5 className={`fw-bold ${project.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`}>
                        {project.paymentStatus}
                      </h5>
                    </div>
                  </div>
                </div>

                <div className="mb-5">
                  <div className="d-flex justify-content-between mb-2">
                    <h6 className="fw-bold">प्रोजेक्टची प्रगती (Work Progress)</h6>
                    <span className="fw-bold text-primary">{project.progress}%</span>
                  </div>
                  <div className="progress rounded-pill shadow-sm" style={{ height: '25px' }}>
                    <div 
                      className={`progress-bar progress-bar-striped progress-bar-animated ${project.progress === 100 ? 'bg-success' : 'bg-primary'}`} 
                      style={{ width: `${project.progress}%` }}
                    ></div>
                  </div>
                  <p className="mt-3 text-muted">सध्याची स्थिती: <strong>{project.status}</strong></p>
                </div>

                <div className="alert alert-info border-0 rounded-3">
                  <i className="fas fa-info-circle me-2"></i>
                  तुमच्या प्रोजेक्टचे लाइव्ह अपडेट्स येथे दिसतील. काही शंका असल्यास आमच्याशी संपर्क साधा.
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default ClientDashboard;
